<span class="line">red<span class="token punctuation">[</span><span class="token number">150</span><span class="token punctuation">:</span><span class="token number">350</span><span class="token punctuation">,</span> <span class="token number">150</span><span class="token punctuation">:</span><span class="token number">350</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">255</span></span>
