<span class="line">    blue_img <span class="token operator">=</span> Image<span class="token punctuation">.</span>fromarray<span class="token punctuation">(</span><span class="token punctuation">(</span>blue<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span>convert<span class="token punctuation">(</span><span class="token string">&quot;L&quot;</span><span class="token punctuation">)</span></span>
